dtsPropsFor.Badge:
/** Halal-status / ownership tier the pill renders. */
type: "muis" | "admin" | "owned" | "friendly" | "nopork" | "pending" | "family" | "prayer";
/** Larger pill for headers / detail pages. */
lg?: boolean;

dtsPropsFor.StatCard:
label: string;
value: string | number;
/** Signed period-over-period change; null/undefined hides the delta badge (never a fake 0%). */
delta?: number | null;
deltaLabel?: string;
hint?: string;
/** Icon name from the shared Icon set (e.g. "store", "eye", "dollar"). */
icon?: string;

dtsPropsFor.ListingCard:
/** Directory business record. Reads id/slug, name, cuisine, area, rating, reviews, badges, blurb, image, open, distance, featured, franchise/outletCount, claimed. */
item: {
  id: string; slug?: string; name: string; cat?: string; cuisine: string; area: string;
  rating: number; reviews: number; badges: string[]; blurb: string;
  image?: string; img?: string; tone?: string; open: boolean; distance?: string;
  featured?: boolean; franchise?: boolean; outletCount?: number; claimed?: boolean;
  [key: string]: unknown;
};
variant?: "standard" | "featured" | "row";
/** Analytics hook fired when the card's main link opens. */
onOpen?: () => void;

dtsPropsFor.Icon:
/** Key into the shared 24x24 stroke-icon set (e.g. "search", "starf", "mosque", "shield-check"). Unknown names fall back to the "info" glyph; "starf" renders filled, "google" is a special multi-colour mark. */
name: string;
/** Width & height in px. Default 20. */
size?: number;
/** SVG stroke width (ignored for the filled "starf"). Default 1.9. */
strokeWidth?: number;
style?: CSSProperties;
className?: string;

dtsPropsFor.Logo:
/** Click handler; when set the logo becomes a keyboard-accessible role="button". */
onClick?: () => void;
/** Render for dark backgrounds — the wordmark flips to white (crescent stays gold). */
light?: boolean;

dtsPropsFor.Rating:
/** Numeric score, shown to one decimal (value.toFixed(1)). */
value: number;
/** Review count. Exactly 0 renders the honest "New" state (never a fabricated score); undefined = unknown, count hidden. */
count?: number;
/** Show the "(count)" suffix. Default true. */
showCount?: boolean;

dtsPropsFor.ImagePh:
/** Alt text for the loaded image (no visible label is rendered). */
label?: string;
/** Placeholder ground tone: "cream" (default) | "gold" | "emerald". */
tone?: string;
/** CSS aspect-ratio applied to the box (e.g. "4 / 3"). */
ratio?: string;
/** Placeholder glyph name shown while empty/loading. Default "camera". */
icon?: string;
style?: CSSProperties;
className?: string;
/** Image source; when absent or broken the placeholder/fallback shows instead. */
src?: string;
/** next/image sizes attribute. Default "(max-width: 768px) 100vw, 400px". */
sizes?: string;
priority?: boolean;
/** Honest, business-specific empty state shown when src is absent or broken. */
fallback?: ReactNode;

dtsPropsFor.BusinessMediaFallback:
/** Business name; its first letter becomes the artwork's initial mark. */
name: string;
/** Category label shown in the sub-line (full mode only). */
category?: string;
/** Area label shown in the sub-line (full mode only). */
area?: string;
/** Collapse to the initial-mark tile only (hides copy). Default false. */
compact?: boolean;

dtsPropsFor.CategoryButton:
/** Category descriptor: an icon name + a display label. */
cat: { icon: string; label: string };
onClick?: () => void;

dtsPropsFor.SectionHead:
/** Section title (rendered as an <h2> in the Spectral serif). */
title: string;
/** Optional action-link text; the chevron + link only render when set. */
action?: string;
/** Handler for the action link (makes it a keyboard-accessible role="button"). */
onAction?: () => void;

dtsPropsFor.Empty:
/** Glyph name for the header chip. Default "search". */
icon?: string;
title?: string;
body?: string;
/** Optional CTA label; the button only renders when set. */
action?: string;
onAction?: () => void;

dtsPropsFor.MobileHeader:
/** Centered title text (Spectral serif). */
title?: string;
/** Back-button handler (button is always shown). */
onBack?: () => void;
/** Optional right-slot node (e.g. a share/overflow icon button). */
right?: ReactNode;

dtsPropsFor.SearchBar:
value: string;
onChange: (v: string) => void;
onSubmit?: (v: string) => void;
placeholder?: string;
autoFocus?: boolean;
suggest?: boolean;

dtsPropsFor.Stepper:
label: string;
sub?: string;
value: number;
min?: number;   // default 0
max?: number;   // default 16
onChange: (v: number) => void;

dtsPropsFor.ProgressRing:
value: number;        // 0..1, clamped; non-finite -> empty track
size?: number;        // default 96
stroke?: number;      // default ~size/12; pass ~size/6 for a donut
tone?: "emerald" | "gold" | "danger";
children?: ReactNode; // center content
label?: string;       // exposes role="meter" when set
className?: string;
style?: CSSProperties;

dtsPropsFor.OwnerOfferCard:
plan: string;
toast: (m: string) => void;
onUpgrade: () => void;

dtsPropsFor.RatingBadge:
score: number;
count?: number;
word?: string;
lg?: boolean;

dtsPropsFor.Faq:
items: QA[]; // lib/faq: { q: string; a: string }
title?: string;
eyebrow?: string;
columns?: 1 | 2; // 2 → responsive two-column grid

dtsPropsFor.Newsletter:
source?: string;
variant?: "inline" | "card";
collectName?: boolean;
cta?: string;
stage?: string;
consent?: boolean; // default true; false hides the PDPA line

dtsPropsFor.BlogCard:
/** CardPost = Pick<BlogPost, "slug"|"title"|"dek"|"readMins"|"datePublished"|"image"|"imageAlt"|"category"|"tags"> */
post: {
  slug: string; title: string; dek: string; readMins: number; datePublished: string; // YYYY-MM-DD
  image: string; imageAlt: string; category: BlogCategorySlug; tags: string[];
};
/** Use h2 on the index (SEO heading order); h3 inside grids/rails. */
headingLevel?: "h2" | "h3";
priority?: boolean;
